import{_ as t,a as e,b as d}from"./chunks/配置渠道内容.HzNkdrom.js";import{_ as s,o as n,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Добавление канала GitLab Packages","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/gitlab-packages.md","filePath":"ru-RU/upload/gitlab-packages.md","lastUpdated":1781962217000}'),r={name:"ru-RU/upload/gitlab-packages.md"};function l(c,a,p,b,h,g){return n(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="добавление-канала-gitlab-packages" tabindex="-1">Добавление канала GitLab Packages <a class="header-anchor" href="#добавление-канала-gitlab-packages" aria-label="Permalink to &quot;Добавление канала GitLab Packages&quot;">​</a></h1><h2 id="что-подготовить-заранее" tabindex="-1">Что подготовить заранее <a class="header-anchor" href="#что-подготовить-заранее" aria-label="Permalink to &quot;Что подготовить заранее&quot;">​</a></h2><p>Нужны всего три вещи:</p><table tabindex="0"><thead><tr><th>Что нужно</th><th>Зачем это нужно</th></tr></thead><tbody><tr><td>Аккаунт GitLab</td><td>Для создания access token и владения проектом.</td></tr><tr><td>GitLab Personal Access Token</td><td>ImgBed использует его для доступа к GitLab API, создания проектов и загрузки файлов в Generic Packages.</td></tr><tr><td>Имя проекта</td><td>Можно ввести только имя проекта, например <code>imgbed</code>.</td></tr></tbody></table><h2 id="настроика" tabindex="-1">Настройка <a class="header-anchor" href="#настроика" aria-label="Permalink to &quot;Настройка&quot;">​</a></h2><h3 id="шаг-1-воидите-в-gitlab-и-создаите-access-token" tabindex="-1">Шаг 1. Войдите в GitLab и создайте Access Token <a class="header-anchor" href="#шаг-1-воидите-в-gitlab-и-создаите-access-token" aria-label="Permalink to &quot;Шаг 1. Войдите в GitLab и создайте Access Token&quot;">​</a></h3><ol><li>Войдите в GitLab.</li><li>Нажмите аватар в правом верхнем углу и откройте <code>Preferences</code>.</li><li>В левой боковой панели откройте <code>Access Tokens</code>.</li><li>Дайте token понятное имя.</li><li>Выберите срок действия по своему подходу к обслуживанию.</li><li>Выберите scope <code>api</code>.</li><li>Сразу после создания скопируйте и сохраните token.</li></ol><p><img src="'+t+'" alt="Создание legacy token" loading="lazy"></p><p><img src="'+e+'" alt="Выбор прав token" loading="lazy"></p><h2 id="шаг-2-заполните-канал-gitlab-packages-в-imgbed" tabindex="-1">Шаг 2. Заполните канал GitLab Packages в ImgBed <a class="header-anchor" href="#шаг-2-заполните-канал-gitlab-packages-в-imgbed" aria-label="Permalink to &quot;Шаг 2. Заполните канал GitLab Packages в ImgBed&quot;">​</a></h2><p>После выбора <code>GitLab Packages</code> в настройках загрузки заполните поля:</p><table tabindex="0"><thead><tr><th>Поле в интерфейсе</th><th>Что ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Имя на ваш выбор, например <code>GitLabPrimary</code>.</td></tr><tr><td>Access Token</td><td>GitLab Personal Access Token, который вы только что создали.</td></tr><tr><td>Project name</td><td>Короткое имя проекта, например <code>imgbed</code>, или полный путь вроде <code>username/imgbed</code>.</td></tr><tr><td>Private repository</td><td>Включите или выключите по своим потребностям.</td></tr><tr><td>Remark</td><td>Необязательно, например <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+d+`" alt="Настройка канала" loading="lazy"></p><h2 id="шаг-3-сохраните-канал" tabindex="-1">Шаг 3. Сохраните канал <a class="header-anchor" href="#шаг-3-сохраните-канал" aria-label="Permalink to &quot;Шаг 3. Сохраните канал&quot;">​</a></h2><p>После заполнения полей нажмите Save.</p><p>Система сама обработает:</p><table tabindex="0"><thead><tr><th>Поведение системы</th><th>Описание</th></tr></thead><tbody><tr><td>Короткое имя проекта</td><td>ImgBed определяет текущий аккаунт GitLab и разворачивает значение в полный путь проекта.</td></tr><tr><td>Полный путь проекта</td><td>ImgBed использует путь <code>username/project</code> ровно в том виде, как он введен.</td></tr><tr><td>Проверка проекта</td><td>Если используется путь текущего личного аккаунта, ImgBed автоматически создает проект, если его еще нет. Если полный путь введен вручную, ImgBed использует его напрямую.</td></tr><tr><td>Публичный или приватный статус</td><td>Видимость проекта синхронизируется с текущим переключателем.</td></tr></tbody></table><h2 id="короткии-чек-лист" tabindex="-1">Короткий чек-лист <a class="header-anchor" href="#короткии-чек-лист" aria-label="Permalink to &quot;Короткий чек-лист&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Войти в GitLab</span></span>
<span class="line"><span>-&gt; Создать Access Token</span></span>
<span class="line"><span>-&gt; Выбрать только scope api</span></span>
<span class="line"><span>-&gt; Вернуться в ImgBed и ввести token и имя проекта</span></span>
<span class="line"><span>-&gt; Сохранить</span></span>
<span class="line"><span>-&gt; Если введено только имя проекта, ImgBed автоматически добавит текущий username</span></span>
<span class="line"><span>-&gt; Если введено username/project, ImgBed использует это как есть</span></span>
<span class="line"><span>-&gt; Загрузить тестовое изображение</span></span></code></pre></div>`,19)])])}const _=s(r,[["render",l]]);export{u as __pageData,_ as default};
